@namespace Lumeo

@{
    var context = new DialogContext(EffectiveOpen, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss, _descriptionRegistry, RegisterDescription, UnregisterDescription);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    /// <summary>The dialog's trigger and content, typically a <see cref="DialogTrigger"/> and <see cref="DialogContent"/>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Whether the dialog is open. Two-way bindable via <see cref="OpenChanged"/>; when neither this nor <see cref="OpenChanged"/> is supplied, the dialog manages its own state internally, seeded from <see cref="DefaultOpen"/>.</summary>
    [Parameter] public bool Open { get; set; }
    /// <summary>Raised when the open state changes, e.g. via <see cref="DialogTrigger"/>, Escape, a backdrop click, or <see cref="DialogClose"/>.</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Uncontrolled initial open state. Used only when the consumer does NOT
    /// bind <see cref="Open"/> (Radix <c>defaultOpen</c>): the dialog then owns
    /// its open state internally, seeded from this value. When <see cref="Open"/>
    /// is supplied the component is controlled and this is ignored.
    /// </summary>
    [Parameter] public bool DefaultOpen { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape, backdrop click,
    /// X button, or a <c>DialogClose</c> trigger). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort the
    /// dismiss — useful for "discard unsaved changes?" guards.
    /// Inspect <see cref="DismissEventArgs.Reason"/> to find out which
    /// gesture asked to close.
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    /// <summary>Legacy alias for <see cref="Open"/>.</summary>
    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    /// <summary>Legacy alias for <see cref="OpenChanged"/>.</summary>
    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("dialog-title");
    private readonly string _descriptionId = LumeoIds.New("dialog-desc");

    // Tracks whether a <DialogDescription> is actually present in the tree. A
    // mutable holder (not a record field) because the cascaded context is
    // rebuilt every render, but the registration must persist across renders.
    // Mirrors AlertDialog's DescriptionRegistry — without this DialogContent
    // would emit a dangling aria-describedby IDREF whenever no description is
    // rendered (e.g. every service-opened overlay).
    private readonly DialogDescriptionRegistry _descriptionRegistry = new();

    // Uncontrolled state. _controlled is set in SetParametersAsync when the
    // consumer supplies Open/IsOpen; otherwise the dialog owns _open (Radix
    // controlled-vs-uncontrolled disambiguation — a bool param can't be
    // "undefined", so we inspect which parameters were actually provided).
    private bool _controlled;
    private bool _open;

    // The last Open value the PARENT actually supplied. We seed the working
    // _open backing field from this only when the parent genuinely changes it,
    // so an internal close (Escape / backdrop / DialogClose) is not clobbered by
    // a subsequent parent re-render that re-pushes the same Open literal. This
    // is the state-on-data-change guard: live close-state lives in _open, never
    // in the [Parameter] Open. _hasOpenParam tracks whether we've observed a
    // first value yet (so the very first render seeds, even for Open == false).
    private bool _lastOpenParam;
    private bool _hasOpenParam;
    // CONTROLLED discriminator: the last value we pushed UP via OpenChanged (also
    // re-synced whenever we adopt an authoritative Open). A controlled parent
    // re-render that echoes back this exact value is safe to ignore (keep
    // in-flight state); any other value is an authoritative assertion (veto /
    // normalization / reset) and must win — this is what rolls a vetoed close
    // back to the parent's rejected value instead of leaving the dialog stuck
    // showing the rejected state forever.
    private bool _lastPushedOpen;

    // In both controlled and uncontrolled mode the rendered state is the working
    // _open backing field. In controlled mode _open is reseeded from Open in
    // SetParametersAsync whenever the parent actually changes it (see above), so
    // the parent stays authoritative on real changes while an internal close
    // survives a same-value re-render — the fix for one-way controlled dialogs
    // (Open supplied, OpenChanged unbound) that previously could not stay closed.
    private bool EffectiveOpen => _open;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // The legacy IsOpen alias is obsolete but still a valid bound parameter,
        // so we must honour it when deciding controlled-ness (suppress CS0618 for
        // the nameof — we're intentionally probing the alias).
#pragma warning disable CS0618
        var hasOpen = parameters.TryGetValue<bool>(nameof(Open), out var incomingOpen)
            || parameters.TryGetValue<bool>(nameof(IsOpen), out incomingOpen);
        _controlled = hasOpen || OpenChanged.HasDelegate;
#pragma warning restore CS0618

        // Reseed the working state from the parent ONLY on a real change (first
        // observation, or an authoritative assertion). Done before
        // base.SetParametersAsync so the render it queues already sees the
        // correct _open on the very first parameter set.
        if (hasOpen)
        {
            if (OpenChanged.HasDelegate)
            {
                // CONTROLLED: the parent owns the value via OpenChanged. Echo of
                // our own push (incomingOpen == _lastPushedOpen) → keep in-flight
                // state (an internal close still pending the parent's
                // re-render). Anything else — veto, normalization, reset, or the
                // very first observation — is an authoritative assertion from
                // the parent and must win. This is what rolls a vetoed close
                // (parent re-renders with Open unchanged) back to the rejected
                // value instead of permanently showing the optimistic state.
                if (!_hasOpenParam || incomingOpen != _lastPushedOpen)
                {
                    _open = incomingOpen;
                    _lastPushedOpen = incomingOpen;
                    _hasOpenParam = true;
                }
            }
            else if (!_hasOpenParam || incomingOpen != _lastOpenParam)
            {
                // UNCONTROLLED (Open supplied, OpenChanged unbound): adopt only
                // when the parent genuinely changes the value, so a same-value
                // re-render must NOT overwrite an internal close — that is
                // exactly what let a one-way controlled dialog silently reopen
                // after the user dismissed it.
                _open = incomingOpen;
                _lastPushedOpen = incomingOpen;
                _hasOpenParam = true;
            }

            // Keep the uncontrolled discriminator pointing at the last Open we
            // observed, even in controlled mode, so a parent that later unbinds
            // OpenChanged falls back to accurate state-on-data-change tracking.
            _lastOpenParam = incomingOpen;
        }

        return base.SetParametersAsync(parameters);
    }

    protected override void OnInitialized()
    {
        // Uncontrolled dialogs seed their open state from DefaultOpen. Controlled
        // dialogs were already seeded from Open in SetParametersAsync.
        if (!_controlled) _open = DefaultOpen;
    }

    private async Task SetOpen(bool value)
    {
        // Update the working backing field only — NEVER the [Parameter] Open.
        // OpenChanged notifies two-way @bind-Open / controlled consumers; the
        // local _open carries the live state so a one-way controlled parent that
        // does not handle OpenChanged still observes the close until it chooses to
        // re-assert Open. If the parent later pushes a genuinely different Open,
        // SetParametersAsync reseeds _open and the parent regains authority.
        _open = value;
        // Record _lastPushedOpen BEFORE invoking OpenChanged: a controlled parent
        // re-renders synchronously inside InvokeAsync, so SetParametersAsync must
        // already see this value as "the value we just pushed" to distinguish an
        // accepted echo (keep in-flight state) from a veto (parent kept its old
        // value → roll back to it).
        _lastPushedOpen = value;
        // Deliberately do NOT touch _lastOpenParam here: it still holds the value
        // the parent last supplied as a [Parameter], independent of what we just
        // pushed. The UNCONTROLLED branch in SetParametersAsync compares against
        // that, so a plain parent re-render that re-pushes the same literal (with
        // no OpenChanged handler listening) does not revert our internal toggle.
        await OpenChanged.InvokeAsync(value);
        // Re-render so the cascaded context picks up EffectiveOpen. The close
        // paths (Escape / backdrop / DialogClose) call this via TryDismiss as a
        // direct method call — without an explicit StateHasChanged an uncontrolled
        // dialog (no OpenChanged) would never re-render and so never close.
        StateHasChanged();
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    // Called by DialogDescription on init so DialogContent only wires
    // aria-describedby when a description actually exists (no dangling IDREF).
    // Re-renders so the content's aria-describedby picks up the registration on
    // the next pass (child OnInitialized runs after the parent's first render).
    // Counted (not a bool) so a description that is conditionally REMOVED while
    // the dialog stays mounted is correctly un-registered via UnregisterDescription
    // below (Codex P2) — a bare bool latched true forever and left aria-describedby
    // pointing at an id no longer in the DOM once the description disappeared.
    private void RegisterDescription()
    {
        _descriptionRegistry.Count++;
        if (_descriptionRegistry.Count == 1) StateHasChanged();
    }

    // Called by DialogDescription.Dispose when it is removed from the tree (a
    // conditionally-rendered <DialogDescription>, or the dialog itself closing).
    // Only re-renders on the 1->0 transition, so multiple descriptions removing in
    // the same batch don't thrash StateHasChanged.
    private void UnregisterDescription()
    {
        _descriptionRegistry.Count--;
        if (_descriptionRegistry.Count == 0) StateHasChanged();
    }

    // DescriptionRegistry + RegisterDescription/UnregisterDescription default to null! so the 4.0
    // additions stay a non-breaking signature change: Lumeo always constructs the context with real
    // values, and any external 3.x constructor of the 5-arg shape still compiles.
    public record DialogContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss, DialogDescriptionRegistry DescriptionRegistry = null!, Action RegisterDescription = null!, Action UnregisterDescription = null!);

    /// <summary>
    /// Persistent, mutable holder that survives the per-render rebuild of
    /// <see cref="DialogContext"/>. Lets <see cref="DialogContent"/> know whether
    /// a <see cref="DialogDescription"/> is CURRENTLY rendered so it can avoid
    /// emitting a dangling <c>aria-describedby</c> IDREF (mirrors the AlertDialog
    /// pattern). A count, not a bool: a description that mounts then is later
    /// removed must un-register, which a one-way-latched bool cannot represent.
    /// </summary>
    public sealed class DialogDescriptionRegistry
    {
        public int Count { get; set; }
        public bool HasDescription => Count > 0;
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<div id="@_id" class="@CssClass" role="button" tabindex="0" @onclick="Close" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Dialog.DialogContext Context { get; set; } = default!;
    /// <summary>The close trigger's content, e.g. a "Cancel" button.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the trigger element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the trigger element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _fallbackId = LumeoIds.New("dialog-close");
    // A consumer-supplied id (splatted) wins, so JS key-suppression must target THAT id.
    private string _id => LumeoIds.Effective(AdditionalAttributes, _fallbackId);
    private bool _pdRegistered;

    private string CssClass => Cx.Merge("inline-flex", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _pdRegistered) return;
        try
        {
            // div[role=button] has no native key synthesis: Space both activated AND
            // scroll-jumped the page. Suppress only Space's default synchronously in
            // JS (Enter has no default on a div; a blanket @onkeydown:preventDefault
            // would also swallow Tab). Mirrors CollapsibleTrigger / AccordionTrigger.
            await Interop.RegisterPreventDefaultKeys(
                _id,
                new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // close from a custom button just like the built-in X / Escape paths.
    private async Task Close() => await Context.TryDismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Close();
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_id);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable
@implements IOverlayExitCallback

@if (Shell is not null)
{
    @* See OverlayShellMarker — host DialogContent already painted the shell.
       Pass children through to avoid a second backdrop + panel. *@
    @ChildContent
}
else if (Context.IsOpen || _exiting)
{
    @* pointer-events-none on the full-viewport wrapper + pointer-events-auto on
       backdrop/panel: the wrapper itself must never be a hit-target. If a panel
       ever wedges off-screen (e.g. an interrupted entry animation on a mobile
       viewport shift), an input-eating invisible full-screen layer is exactly the
       "overlay can't be closed and blocks everything below" failure mode reported
       for stacked service overlays — this makes it structurally impossible. *@
    <div class="fixed inset-0 flex items-center justify-center pointer-events-none" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware overlay token. Uses the --color-overlay-backdrop
           CSS variable (defined + light/dark-swapped in lumeo.css) directly via
           inline style rather than a Tailwind utility, so it resolves for every
           consumer of the pre-built bundle without depending on the token class
           being safelisted (same approach as Tour's SVG scrim). Fades out
           alongside the panel while exiting (service-opened dialogs only —
           see PlayExitAnimation). *@
        <div class="@BackdropClass" style="background-color:var(--color-overlay-backdrop);z-index:@BackdropZ" @onclick="HandleBackdropClick"></div>
        <!-- Content -->
        @* @onkeydown:stopPropagation — a modal surface owns the keys pressed
           inside it. Nested overlays render INSIDE this div, so their keydown
           events bubble here; without this, an Escape already handled by an
           inner Dialog/Sheet/Drawer/AlertDialog would also fire this dialog's
           Escape handler and cascade-close every ancestor overlay. The
           directive is static (stops ALL keydown propagation at this element's
           boundary), which is safe for a modal: descendants still receive
           their events first — propagation is only cut once it reaches this
           div — and nothing outside an open modal should react to its keys. *@
        @* While exiting (Context.IsOpen == false, panel kept mounted for the
           zoom-out), the focus trap + scroll lock are already torn down, so the
           panel is no longer modal — advertise aria-modal="false" so ARIA matches
           the live behaviour (mirrors SheetContent #185). *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="dialog" aria-modal="@(Context.IsOpen ? "true" : "false")" aria-labelledby="@Context.TitleId" aria-describedby="@DescribedBy" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" inert="@ExitInert" @attributes="AdditionalAttributes">
            @if (Scrollable)
            {
                @* overflow-x-hidden: a child with the -mx-1 focus-ring gutter
                   (OverlayForm's body) is 8px wider than this scrollport; without
                   the explicit x-clip, overflow-y:auto promotes overflow-x to auto
                   and the 4px overhang grows a spurious horizontal scrollbar. *@
                <div class="max-h-[85vh] overflow-y-auto overflow-x-hidden">
                    @ChildContent
                </div>
            }
            else
            {
                @ChildContent
            }
            @* lumeo-dialog-close: stable consumer hook (restyle/hide without relying
               on utility-class internals). z-10 keeps the X clickable above any
               positioned child a consumer renders full-bleed (sticky headers etc.),
               which previously painted over the un-z-indexed button. *@
            @if (ShowCloseButton ?? !PreventClose)
            {
                <button type="button" aria-label="@L["Dialog.Close"]" class="lumeo-dialog-close absolute end-2 top-2 sm:end-4 sm:top-4 z-10 inline-flex items-center justify-center rounded-sm h-11 w-11 sm:h-6 sm:w-6 opacity-70 transition-opacity hover:opacity-100 focus:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2" @onclick="HandleCloseButton">
                    <SvgGlyph Svg="@(LumeoIcons.X)" class="h-4 w-4" />
                    <span class="sr-only">@L["Dialog.Close"]</span>
                </button>
            }
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Dialog.DialogContext Context { get; set; } = default!;
    [CascadingParameter] public OverlayShellMarker? Shell { get; set; }
    /// <summary>The dialog panel's content, typically <see cref="DialogHeader"/>, <see cref="DialogTitle"/>, <see cref="DialogDescription"/>, and <see cref="DialogFooter"/>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Disables the Escape key and backdrop click as dismiss gestures, and (unless <see cref="ShowCloseButton"/> forces it) hides the X button — leaving only an explicit <see cref="DialogClose"/> (or programmatic close) able to dismiss the dialog.</summary>
    [Parameter] public bool PreventClose { get; set; }
    /// <summary>Whether the top-end close (X) button renders. <c>null</c> (default)
    /// keeps the legacy coupling — X shows whenever <see cref="PreventClose"/> is
    /// <c>false</c>. <c>true</c> forces the X even on a modal dialog (backdrop/Escape
    /// stay disabled; the X still routes through the dismiss guard so an
    /// <c>OnBeforeClose</c> veto applies); <c>false</c> hides it for fully custom
    /// close chrome. Mirrors <c>OverlayOptions.ShowCloseButton</c> for service dialogs.</summary>
    [Parameter] public bool? ShowCloseButton { get; set; }
    /// <summary>Controls the panel's max width, from <see cref="DialogSize.Sm"/> up to <see cref="DialogSize.Full"/>. Default <see cref="DialogSize.Default"/>.</summary>
    [Parameter] public DialogSize Size { get; set; } = DialogSize.Default;
    /// <summary>Caps the panel at <c>85vh</c> and makes its content vertically scrollable, so a tall body doesn't overflow the viewport.</summary>
    [Parameter] public bool Scrollable { get; set; }
    /// <summary>When <c>true</c> (the default), closing the dialog keeps the panel
    /// mounted for a brief zoom-out (and backdrop fade-out) before unmounting,
    /// instead of vanishing instantly — so a declarative <c>&lt;DialogContent&gt;</c>
    /// animates its close the same way a declarative Sheet already does, and the
    /// same way <see cref="OverlayProvider"/> already animates service-opened
    /// dialogs. Set to <c>false</c> to opt OUT (immediate unmount on close) for
    /// tests or consumers who want an instant dismiss.</summary>
    [Parameter] public bool PlayExitAnimation { get; set; } = true;
    /// <summary>Additional CSS classes merged onto the dialog panel.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>
    /// Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults to
    /// <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay so a Dialog opened
    /// from inside another Dialog stacks above instead of colliding.
    /// </summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;
    /// <summary>Captures any unmatched attributes and applies them to the dialog panel.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("dialog");
    // True once we've rendered open and not yet processed the close. Drives the
    // exit animation INDEPENDENTLY of whether the open-interop finished — a dismiss
    // during the Blazor Server interop round-trip window still zooms out instead of
    // vanishing (the B11 "no exit animation on real apps" regression). See
    // SheetContent for the full write-up.
    private bool _shownOpen;
    // True once the open-interop chain (scroll lock + focus trap + slide-end) has
    // run and needs tearing down on close. On Server the panel is visible and
    // dismissable before this flips true.
    private bool _interopReady;
    // Exit-animation state: true between the close request and the moment the
    // zoom-out finishes, keeping the panel mounted so the user sees it leave
    // instead of vanishing. Only ever set when PlayExitAnimation is true
    // (service-opened dialogs). Driven by _exitDispatch.
    private bool _exiting;
    private readonly Lumeo.Services.DelayedDispatch _exitDispatch = new();
    // Radix-Presence parity: the real unmount is driven by the panel's own
    // animationend (attachOverlayExitEnd), which also clears the open-time inline
    // animation:none guard so the zoom-out can run. _exitDispatch is the fallback.
    private DotNetObjectReference<DialogContent>? _selfRef;
    private bool _exitWired;

    // FALLBACK window only — the real unmount is the panel's animationend
    // (OnExitAnimationEnd). Sits above the 0.15s zoom-out so the timer never
    // preempts a slightly-late animationend; it covers only the JS-dead /
    // lost-event case. 0 only when the exit animation is opted OUT
    // (PlayExitAnimation=false) → immediate unmount.
    private int ExitDurationMs => PlayExitAnimation ? 280 : 0;

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    // Backdrop fades in on open, fades out while the panel exits. It KEEPS
    // pointer-events-auto through the exit so it goes on shielding the page beneath
    // until it unmounts — a modal backdrop's job is to block the page until it is
    // gone (Radix keeps the overlay blocking until close completes), so a fast
    // double-click during the fade lands on the scrim, not on the page below.
    // HandleBackdropClick is already a no-op while exiting (it gates on
    // Context.IsOpen), so swallowing that click can't re-trigger a dismiss/reopen.
    // The PANEL, by contrast, stays pointer-events-none + inert (PointerClass).
    private string BackdropClass => _exiting
        ? "fixed inset-0 animate-fade-out pointer-events-auto"
        : "fixed inset-0 animate-fade-in pointer-events-auto";

    // Enter counterpart is animate-zoom-in (baked into CssClass); on exit the
    // panel zooms back out toward its dismissed state.
    private string AnimationClass => _exiting ? "animate-zoom-out" : "animate-zoom-in";

    // Exit-window inertness (mirrors DropdownMenuContent). While the panel is kept
    // mounted for the zoom-out (Context.IsOpen == false, _exiting == true) its focus
    // trap + scroll lock are already torn down by Cleanup(), so the still-painted
    // panel is a clickable/tabbable ghost. pointer-events-none + inert make it inert
    // for the fade: a stray click or Tab can't re-enter a closing dialog. Focus was
    // restored to the trigger by RemoveFocusTrap at close time (before/independent of
    // this), so inert here traps nothing. The wrapper is pointer-events-none, so the
    // OPEN panel must re-enable pointer-events-auto explicitly — hence the toggle.
    private string PointerClass => _exiting ? "pointer-events-none" : "pointer-events-auto";
    private string? ExitInert => _exiting ? "true" : null;

    // Only reference the description id when a <DialogDescription> was actually
    // rendered; otherwise aria-describedby would dangle to a missing element
    // (returning null makes Blazor omit the attribute entirely). This is what
    // every service-opened Dialog (no description child) hits.
    private string? DescribedBy => Context.DescriptionRegistry.HasDescription ? Context.DescriptionId : null;

    private string SizeClass => Size switch
    {
        DialogSize.Sm => "max-w-sm",
        DialogSize.Default => "max-w-lg",
        DialogSize.Lg => "max-w-2xl",
        DialogSize.Xl => "max-w-4xl",
        DialogSize.Full => "max-w-[calc(100vw-2rem)] max-h-[calc(100vh-2rem)]",
        _ => "max-w-lg"
    };

    private string CssClass => Cx.Merge("relative grid w-full", SizeClass, "gap-4 bg-background p-6 shadow-lg sm:rounded-lg", AnimationClass, PointerClass, Class);

    protected override void OnParametersSet()
    {
        if (Shell is not null) return;

        // The exit animation is driven ENTIRELY here, from the open->closed render
        // transition, so it no longer depends on the open-interop having finished
        // (the old `_wasOpen` gate). On Blazor Server the open interop is a chain of
        // round-trips; a dismiss can land while it's still in flight — keying the
        // zoom-out off `_shownOpen` (flipped true the instant we first render open)
        // makes it play whenever the dismiss arrives, and scheduling the unmount
        // here means the panel is never stranded mounted. Opting the exit OUT
        // (PlayExitAnimation=false) keeps ExitDurationMs == 0 → immediate unmount.
        // (B11.)
        if (Context.IsOpen)
        {
            if (_exiting)
            {
                _exitDispatch.Cancel();
                _exiting = false;
                _exitWired = false;
            }
            _shownOpen = true;
        }
        else if (_shownOpen)
        {
            _shownOpen = false;
            if (ExitDurationMs > 0)
            {
                _exiting = true;
                _exitWired = false;
                _exitDispatch.Schedule(ExitDurationMs, () => InvokeAsync(FinishExit));
            }
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Passthrough mode — host DialogContent owns lifecycle effects.
        if (Shell is not null) return;

        if (Context.IsOpen && !_interopReady)
        {
            // Mark BEFORE the awaits so a dismiss that Server dispatches between the
            // interop round-trips still hits the undo-check below exactly once.
            _interopReady = true;
            // Guard the open-branch interop against a circuit teardown that
            // races with this render (e.g. the user navigates away while the
            // dialog is opening). Mirrors Cleanup()'s JSDisconnectedException
            // handling so a disconnect during setup degrades gracefully
            // instead of surfacing an unhandled exception.
            try
            {
                await Interop.LockScroll();
                await Interop.SetupFocusTrap(_contentId);
                // Neutralize the entry animation once it finishes (the Sheet/Drawer
                // rc.25 pattern): animate-zoom-in transform-animates with
                // fill-mode:both, which leaves the settled panel with an
                // identity-matrix transform — and even transform:none plus a live
                // `animation` declaration keeps Chrome treating the panel as a
                // containing block for position:fixed descendants. Without this, a
                // Select/DropdownMenu/DatePicker opened INSIDE the dialog resolves
                // its fixed coordinates against the panel instead of the viewport
                // (the B1 mispositioning report's second ingredient).
                await Interop.AttachOverlaySlideEnd(_contentId);
            }
            catch (JSDisconnectedException) { }

            // Dismissed while the open interop was still in flight (the Server
            // round-trip window that used to swallow the zoom-out): tear the
            // scroll lock / focus trap back down so they aren't left bound to a
            // panel that's already zooming out. The zoom-out itself is owned by
            // OnParametersSet, so it plays regardless.
            if (!Context.IsOpen)
            {
                await Cleanup();
                _interopReady = false;
            }
        }
        else if (!Context.IsOpen && _interopReady)
        {
            // Close: tear down scroll-lock / focus-trap (focus returns to the
            // trigger now). The zoom-out + deferred unmount are already scheduled
            // by OnParametersSet — this branch is interop teardown only.
            await Cleanup();
            _interopReady = false;
        }

        // Radix-Presence parity: hand the unmount to the panel's OWN exit
        // animationend. attachOverlayExitEnd first strips the open-time inline
        // animation:none/transform:none guard (otherwise it overrides the
        // animate-zoom-out class and the panel can't move — the B11 root cause),
        // then notifies OnExitAnimationEnd once the zoom-out finishes so the
        // backdrop + panel drop together. _exitDispatch stays armed as a fallback.
        if (_exiting && !_exitWired)
        {
            _exitWired = true;
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (JSDisconnectedException) { }
        }
    }

    // Invoked from JS (attachOverlayExitEnd) when the panel's exit animation ends.
    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    // Ends the exit phase: cancel the fallback timer and drop backdrop + panel in
    // the same render commit. Idempotent with the fallback timer.
    private void FinishExit()
    {
        if (!_exiting) return;
        _exitDispatch.Cancel();
        _exiting = false;
        _exitWired = false;
        StateHasChanged();
    }

    // The backdrop / Escape / close paths are inert during the exit phase
    // (Context.IsOpen == false, panel only kept mounted for the zoom-out): its
    // modal affordances were already torn down by Cleanup(), so a stray click /
    // Escape must not re-enter the dismiss flow on an already-closing panel.
    private Task HandleBackdropClick() => !Context.IsOpen || PreventClose ? Task.CompletedTask : Dismiss("outside");

    private Task HandleCloseButton() => Context.IsOpen ? Dismiss("close") : Task.CompletedTask;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && Context.IsOpen && !PreventClose)
        {
            await Dismiss("escape");
        }
    }

    private Task Dismiss(string reason) => Context.TryDismiss(reason);

    private async Task Cleanup()
    {
        try
        {
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        _exitDispatch.Dispose();
        _selfRef?.Dispose();
        if (_interopReady)
        {
            await Cleanup();
        }
    }

    public enum DialogSize { Sm, Default, Lg, Xl, Full }
}

